import { useEffect, useContext } from "react";
import { CartContext } from "../context/CartContext";
import axios from "axios";
import { Link } from "react-router-dom";

function Success() {
  const { cart, setCart } = useContext(CartContext);

  useEffect(() => {
    const userEmail = localStorage.getItem("user");

    if (userEmail && cart.length > 0) {
      const total = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

      axios.post("http://localhost:5000/api/orders/add", {
        userEmail,
        items: cart,
        total,
      });
    }

    // Clear cart
    setCart([]);
    localStorage.removeItem("cart");
  }, []);

  return (
    <div style={{ padding: "40px", textAlign: "center" }}>
      <h1 style={{ color: "green" }}>🎉 Order Placed Successfully!</h1>

      <p style={{ fontSize: "18px", marginTop: "10px" }}>
        Thank you for your purchase. Your order has been saved.
      </p>

      <Link to="/orders">
        <button
          style={{
            marginTop: "20px",
            padding: "12px 25px",
            background: "black",
            color: "white",
            border: "none",
            cursor: "pointer",
            borderRadius: "5px",
          }}
        >
          View My Orders
        </button>
      </Link>

      <Link to="/">
        <button
          style={{
            marginTop: "20px",
            marginLeft: "10px",
            padding: "12px 25px",
            background: "gray",
            color: "white",
            border: "none",
            cursor: "pointer",
            borderRadius: "5px",
          }}
        >
          Continue Shopping
        </button>
      </Link>
    </div>
  );
}

export default Success;
